"use strict";exports.id=212,exports.ids=[212],exports.modules={212:(a,b,c)=>{c.r(b),c.d(b,{default:()=>d});let d={timeline:[{company:"PagBrasil",role:"Product Owner",start:"2025",end:"Present",logo:"/companies/pagbrasil.png",description:"Fintech focused on global payment solutions."},{company:"MULTTI",role:"Product Owner",start:"2023",end:"2025",logo:"/companies/multti.png",description:"Software house focused on multiple industries."},{company:"SigmaTEK",role:"Systems Integration",start:"2022",end:"2023",logo:"/companies/sigmatek.png",description:"CAD/CAM solutions for shop floor operations."},{company:"Unimed",role:"IT Support",start:"2019",end:"2021",logo:"/companies/unimed.png",description:"Systems and solutions for private healthcare."},{company:"Canoastec",role:"Technical Support",start:"2019",end:"2019",logo:"/companies/canoastec.png",description:"Responsible for supporting the entire technology infrastructure of the city of Canoas."}],chapters:[{id:"canoastec",company:"Canoastec",title:"The Beginning",narrative:"My journey started in the public sector, supporting municipal departments in Canoas. It was my first contact with real systems and real problems.",image:"/companies/canoastec.png",backgroundEffect:"grid",steps:[{title:"Technical Support",date:"2018"}]},{id:"unimed",company:"Unimed",title:"Understanding Systems at Scale",narrative:"Working in healthcare taught me how critical reliable systems are. Technology wasn't just infrastructure anymore — it directly impacted people's lives.",image:"/companies/unimed.png",backgroundEffect:"greenGlow",steps:[{title:"IT Support",date:"2019"}]},{id:"sigmatek",company:"SigmaTEK",title:"Integration and Complexity",narrative:"At SigmaTEK I worked with integrations between ERP systems and enterprise platforms. This is where I began understanding the complexity behind digital systems.",image:"/companies/sigmatek.png",backgroundEffect:"integration",steps:[{title:"Systems Integration",date:"2020"}]},{id:"multti",company:"MULTTI",title:"Becoming a Product Owner",narrative:"I have always been a creative person. While working in support I watched systems being built but couldn't influence them. Becoming a Product Owner allowed me to participate in creating solutions.",image:"/companies/multti.png",backgroundEffect:"workflow",steps:[{title:"Product Owner",date:"2021"}]},{id:"pagbrasil",company:"PagBrasil",title:"Building Real Products",narrative:"At PagBrasil I work on API integrations, product delivery and digital solutions. This is where product decisions truly impact real users.",image:"/companies/pagbrasil.png",backgroundEffect:"apiFlow",steps:[{title:"Product & Integrations",date:"2022"}]}]}}};